package com.chaobo.scm.supplier.application.quality;

import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.quality.SupplierQualityEvidenceMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.OffsetDateTime;import java.util.*;
@Service public class SupplierQualityEvidenceApplicationService {private static final Set<String>TYPES=Set.of("INSPECTION","MEDIA","RECTIFICATION","VERIFICATION","LIABILITY");private final SupplierQualityIssueApplicationService issues;private final SupplierQualityEvidenceMapper mapper;private final IdentifierGenerator ids;private final AuditLogRepository audit;public SupplierQualityEvidenceApplicationService(SupplierQualityIssueApplicationService issues,SupplierQualityEvidenceMapper mapper,IdentifierGenerator ids,AuditLogRepository audit){this.issues=issues;this.mapper=mapper;this.ids=ids;this.audit=audit;}@Transactional public long append(long issueId,String type,String url,String content,CommandContext context){context.requirePermission("supplier:quality:evidence:append");var issue=issues.detail(issueId,context.supplierScopeId());if(!TYPES.contains(type)||((url==null||url.isBlank())&&(content==null||content.isBlank())))throw new BusinessException(ErrorCode.VALIDATION_FAILED,"证据类型或内容不合法");long id=ids.nextId();mapper.insert(id,issueId,type,url,content,context.operatorId());audit.save(context,"APPEND_QUALITY_"+type,"QUALITY_ISSUE_EVIDENCE",id,issue.issueNo(),null,"{\"qualityIssueId\":"+issueId+"}");return id;}@Transactional(readOnly=true)public List<View> list(long issueId,Long scope){issues.detail(issueId,scope);return mapper.list(issueId).stream().map(r->new View(r.id(),r.type(),r.url(),r.content(),r.createdBy(),r.createdAt())).toList();}public record View(long id,String type,String attachmentUrl,String content,long createdBy,OffsetDateTime createdAt){}}
